---@type LWnd
local LWnd = LWnd

LWnd.UI_CHILDWND_PATH= "LApp.UI.ctrl.sub."

function LWnd:CreateChildWnd(root,wndName,argList)

    --local wndPara = {
    --    wndName= wndName,
    --    para1 = argList and argList["page"],
    --    para2 = argList and argList["subPage"],
    --    argList = argList,
    --}
    --
    --FireEvent(EventNames.ON_WND_OPEN_TRIGGER,wndPara) --指引触发条件

    local wnd = self:FindChild(wndName)
    if (wnd and not wnd:IsWndClosed()) then
        if (wnd:IsWndMode(LWnd.WND_MODE_UNIQUE)) then
            wnd:SetAsLastSibling()
            wnd:SetWndVisible(true)
            wnd:RefreshWhenOpen(argList)
            return wnd
        end
    end
    return self:CreateChildInternal(root, wndName, argList)

end

function LWnd:CreateChildInternal(root, wndName, argList)
    local wndRef = LxRequire(LWnd.UI_CHILDWND_PATH .. wndName)
    if (wndRef) then
        local wndClass = wndRef:New()
        wndClass:SetWndRoot(root)
        wndClass:SetParentWnd(self)
        if (wndClass:Create(wndName, argList)) then
            return wndClass
        else
            wndClass = nil
        end
    end
    return nil
end

function LWnd:FindChild(wndName)
    if not self._childWnds then
        self._childWnds= {}
    end
    return self._childWnds[wndName]
end

function LWnd:OnChildCreate(child)
    local wndname = child:GetWndName()
    if not self._childWnds then
        self._childWnds= {}
    end
    self._childWnds[wndname] = child

    gLGameUI:RecordChildWnd(child)
end

function LWnd:OnChildClose(child)
    if not self._childWnds then
        return
    end
    local wndname = child:GetWndName()
    self._childWnds[wndname] = nil
    gLGameUI:RemoveChildWnd(wndname)
end

function LWnd:OnChildDestroy(child)

end

function LWnd:CloseChildByName(wndName)
    if not self._childWnds then
        return
    end
    local child = self._childWnds[wndName]
    if child then
        child:WndClose()
    end
    self._childWnds[wndName] = nil
end

function LWnd:CloseAllChild()
    if not self._childWnds then
        return
    end
    local temp ={}
    for k,v in pairs(self._childWnds) do
        temp[k]= v
    end
    for k,v in pairs(temp) do
        v:WndClose()
    end

    self._childWnds =nil

    if gLGameUI then gLGameUI:ClearChildWndRecord() end
end

function LWnd:ResetChildsSortOrder()
    if not self._childWnds then
        return
    end
    for k,v in pairs(self._childWnds) do
        if not v:IsWndClosed() then
            v:ResetChildCanvasAttr()
        end
    end
end

function LWnd:GetChildList()
	return self._childWnds or {}
end


function LWnd:DestroyWndChildEffectAll()
    if not self._childWnds then
        return
    end
    for k,v in pairs(self._childWnds) do
        v:DestroyWndEffectAll()
    end
end